97	@Component({
98	  tag: 'ci-ask-ai',
99	  styleUrl: 'ci-ask-ai.scss',
100	  scoped: true,
101	})
102	export class CiAskAi {
103	  @Element() $el: HTMLElement;
104	  @State() isOpen: boolean = false;
105	  @State() message: string = '';
106	  @State() entries: ChatEntry[] = [];
107	  @State() selectedCategory: string | null = null;
108	  @State() isLoading: boolean = false;
109	  @State() thinkingDots: number = 1;
110	  @State() isWelcomePinned: boolean = false;
111	
112	  private inputRef: HTMLTextAreaElement;
113	  private messagesRef: HTMLDivElement;
114	  private thinkingInterval: number;
115	  private historyIndex: number = -1;
116	  private draftMessage: string = '';
117	  connectedCallback() {
118	    if (isBrowser) {
119	      this.entries = this.loadHistory();
120	    }
121	  }
122	
123	  private loadHistory(): ChatEntry[] {
124	    try {
125	      const raw = localStorage.getItem(STORAGE_KEY);
126	      if (!raw) return [];
127	      return JSON.parse(raw) as ChatEntry[];
128	    } catch {
129	      return [];
130	    }
131	  }
132	
133	  private saveHistory() {
134	    try {
135	      const persistable = this.entries.filter(e => e.role !== 'welcome');
136	      localStorage.setItem(STORAGE_KEY, JSON.stringify(persistable));
137	    } catch {
138	      // storage full or unavailable — silently ignore
139	    }
140	  }
141	
142	  @Listen('keydown', { target: 'document' })
143	  handleDocumentKeyDown(event: KeyboardEvent) {
144	    if (event.key === 'Escape' && this.isOpen && !this.isLoading) {
145	      this.closePopup();
146	      return;
147	    }
148	
149	    if (event.key === 'Tab' && this.isOpen) {
150	      this.trapFocus(event);
151	    }
152	  }
153	
154	  private trapFocus(e: KeyboardEvent) {
155	    const popup = this.$el.querySelector('.ask-ai-popup') as HTMLElement;
156	    if (!popup) return;
157	
158	    const focusable = popup.querySelectorAll<HTMLElement>('button:not([disabled]), textarea:not([disabled]), a[href], [tabindex]:not([tabindex="-1"])');
159	    if (!focusable.length) return;
160	
161	    const first = focusable[0];
162	    const last = focusable[focusable.length - 1];
163	
164	    if (e.shiftKey && document.activeElement === first) {
165	      e.preventDefault();
166	      last.focus();
167	    } else if (!e.shiftKey && document.activeElement === last) {
168	      e.preventDefault();
169	      first.focus();
170	    }
171	  }
172	
173	  private openPopup = (e: MouseEvent) => {
174	    if (!isBrowser) return;
175	    trackAnalyticsEvent(e);
176	    this.isWelcomePinned = false;
177	    this.addWelcomeEntry();
178	    this.isOpen = true;
179	    document.body.style.overflow = 'hidden';
180	    requestAnimationFrame(() => {
181	      this.scrollToBottom();
182	      this.inputRef?.focus();
183	    });
184	  };
185	
186	  private closePopup = () => {
187	    this.isOpen = false;
188	    this.isWelcomePinned = false;
189	    document.body.style.overflow = '';
190	  };
191	
192	  private clearHistory = () => {
193	    if (!window.confirm('Clear chat history?')) return;
194	    this.stopThinking();
195	    this.entries = [{ role: 'welcome' }];
196	    this.message = '';
197	    this.selectedCategory = null;
198	    this.isLoading = false;
199	    this.isWelcomePinned = false;
200	    try {
201	      localStorage.removeItem(STORAGE_KEY);
202	    } catch {
203	      // silently ignore
204	    }
205	  };
206	
207	  private handleBackdropClick = (e: MouseEvent) => {
208	    if (this.isLoading) return;
209	    if ((e.target as HTMLElement).classList.contains('ask-ai-overlay')) {
210	      this.closePopup();
211	    }
212	  };
213	
214	  private handleInput = (e: Event) => {
215	    this.message = (e.target as HTMLTextAreaElement).value;
216	  };
217	
218	  private getUserPrompts(): string[] {
219	    return this.entries.filter(e => e.role === 'user').map(e => e.text);
220	  }
221	
222	  private handleKeyDown = (e: KeyboardEvent) => {
223	    if (e.key === 'Enter' && !e.shiftKey) {
224	      e.preventDefault();
225	      this.handleSend();
226	      return;
227	    }
228	
229	    const prompts = this.getUserPrompts();
230	    if (!prompts.length) return;
231	
232	    if (e.key === 'ArrowUp') {
233	      e.preventDefault();
234	      if (this.historyIndex === -1) {
235	        this.draftMessage = this.message;
236	      }
237	      const nextIndex = Math.min(this.historyIndex + 1, prompts.length - 1);
238	      this.historyIndex = nextIndex;
239	      this.message = prompts[prompts.length - 1 - nextIndex];
240	    } else if (e.key === 'ArrowDown') {
241	      e.preventDefault();
242	      const nextIndex = this.historyIndex - 1;
243	      if (nextIndex < 0) {
244	        this.historyIndex = -1;
245	        this.message = this.draftMessage;
246	      } else {
247	        this.historyIndex = nextIndex;
248	        this.message = prompts[prompts.length - 1 - nextIndex];
249	      }
250	    }
251	  };
252	
253	
254	  private addWelcomeEntry() {
255	    const last = this.entries[this.entries.length - 1];
256	    if (last?.role === 'welcome') return;
257	    this.entries = [...this.entries, { role: 'welcome' }];
258	  }
259	
260	  private toggleCategory = (category: string) => {
261	    if (this.isLoading) return;
262	
263	    if (this.selectedCategory === category) {
264	      this.selectedCategory = null;
265	      return;
266	    }
267	
268	    this.selectedCategory = category;
269	    this.fetchUseCaseProducts(category);
270	  };
271	
272	  private handleExampleClick = (query: string) => {
273	    this.message = query;
274	    requestAnimationFrame(() => {
275	      this.inputRef?.focus();
276	    });
277	  };
278	
279	  private startThinking() {
280	    this.thinkingDots = 1;
281	    this.thinkingInterval = window.setInterval(() => {
282	      this.thinkingDots = (this.thinkingDots % 3) + 1;
283	    }, 250);
284	  }
285	
286	  private stopThinking() {
287	    window.clearInterval(this.thinkingInterval);
288	  }
289	
290	  private scrollToBottom() {
291	    requestAnimationFrame(() => {
292	      if (this.messagesRef) {
293	        this.messagesRef.scrollTop = this.messagesRef.scrollHeight;
294	      }
295	    });
296	  }
297	
298	  private scrollToLastUserMessage() {
299	    requestAnimationFrame(() => {
300	      if (!this.messagesRef) return;
301	      const userMessages = this.messagesRef.querySelectorAll('.ask-ai-message--user');
302	      const last = userMessages[userMessages.length - 1] as HTMLElement;
303	      if (last) {
304	        this.messagesRef.scrollTop = last.offsetTop - this.messagesRef.offsetTop;
305	      }
306	    });
307	  }
308	
309	  private async fetchProducts(query: string): Promise<NeuralSearchResponse> {
310	    const url = new URL(NEURAL_SEARCH_URL);
311	    url.searchParams.set('q', query);
312	    url.searchParams.set('limit', '12');
313	
314	    const response = await fetch(url.toString());
315	    if (!response.ok) {
316	      throw new Error(`Search failed: ${response.status}`);
317	    }
318	    return response.json();
319	  }
320	
321	  private async fetchUseCaseProducts(useCase: string): Promise<void> {
322	    this.entries = [...this.entries, { role: 'user', text: `Search best products for ${useCase}` }];
323	    this.saveHistory();
324	    this.isLoading = true;
325	    this.startThinking();
326	    this.scrollToBottom();
327	
328	    try {
329	      const url = new URL(`${NEURAL_SEARCH_URL}/use-case/${encodeURIComponent(useCase)}`);
330	      url.searchParams.set('limit', '12');
331	
332	      const response = await fetch(url.toString());
333	      if (!response.ok) {
334	        throw new Error(`Search failed: ${response.status}`);
335	      }
336	      const result: UseCaseResponse = await response.json();
337	
338	      if (result.products.length > 0) {
339	        const tag = CATEGORY_TAGS.find(t => t.name === useCase);
340	        const blurb = tag?.blurb || `Best products for ${result.useCase}`;
341	        this.entries = [...this.entries, { role: 'ai', text: blurb, products: result.products, total: result.total }];
342	      } else {
343	        this.entries = [...this.entries, { role: 'ai', text: `No products found for "${result.useCase}". Try a different category.` }];
344	      }
345	    } catch (error) {
346	      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
347	      this.entries = [...this.entries, { role: 'ai', text: `Search failed: ${errorMessage}. Please try again.` }];
348	    } finally {
349	      this.stopThinking();
350	      this.isLoading = false;
351	      this.selectedCategory = null;
352	      this.isWelcomePinned = true;
353	      this.saveHistory();
354	      this.scrollToLastUserMessage();
355	    }
356	  }
