371	    try {
372	      const result = await this.fetchProducts(trimmed);
373	
374	      if (result.products.length > 0) {
375	        this.entries = [
376	          ...this.entries,
377	          { role: 'ai', text: `Found ${result.total} product${result.total !== 1 ? 's' : ''} for "${result.query}"`, products: result.products, total: result.total },
378	        ];
379	      } else {
380	        this.entries = [...this.entries, { role: 'ai', text: `No products found for "${result.query}". Try a different description.` }];
381	      }
382	    } catch (error) {
383	      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
384	      this.entries = [...this.entries, { role: 'ai', text: `Search failed: ${errorMessage}. Please try again.` }];
385	    } finally {
386	      this.stopThinking();
