import { Component, h, State, Listen, Element } from '@stencil/core';
import { isBrowser } from '../../constants/constants';
import { trackAnalyticsEvent } from '../../utils/analytics';

const NEURAL_SEARCH_URL = 'http://localhost:9009/api/v1/neural-search';
const STORAGE_KEY = 'ci-ask-ai-history';

interface CategoryTag {
  name: string;
  tip: string;
  blurb: string;
}

const CATEGORY_TAGS: CategoryTag[] = [
  {
    name: 'Onboarding',
    tip: 'For new hires, we recommend a mix of high-utility tech and soft-touch apparel — T-shirts, pens, notebooks — to ensure they feel the quality on day one.',
    blurb: 'First impressions start with gear that makes new hires feel part of the team from day one.',
  },
  {
    name: 'Trade Shows',
    tip: 'Stand out on the floor with swag people actually keep — promo items, tote bags, sunglasses — curated so your booth is the one they remember.',
    blurb: 'Booths fade from memory, but quality swag travels home — these are the pieces people keep.',
  },
  {
    name: 'Events',
    tip: 'Fundraisers, meetups, community gatherings — T-shirts, tote bags, drinkware, and sunglasses that bring everyone together without stretching the budget.',
    blurb: 'Great events deserve great merch — products that bring everyone together under one look.',
  },
  {
    name: 'Gifting',
    tip: 'Client gifts: tech products, drinkware, bags, foods & candy. Employee gifts: coolers, bags, tech. Leave-behinds: premium brands like Yeti, Stanley, Nike, Ogio.',
    blurb: 'A well-chosen gift says what a thank-you email never could — here are our top picks.',
  },
  {
    name: 'Uniforming',
    tip: 'Schools: polos, T-shirts, hoodies. Corporate: polos, quarter zips, blazers. Small business: polos, T-shirts, long sleeves — durability and professional standards first.',
    blurb: 'A unified look builds trust and professionalism — here is what teams rely on every day.',
  },
  {
    name: 'Spirit Wear',
    tip: 'Schools and teams build identity through sweatshirts, hoodies, sweatpants, T-shirts, and youth sizes — design-forward curation for your specific community.',
    blurb: 'Nothing rallies a community like wearing its colors — fan favorites for every age.',
  },
  {
    name: 'Team & Club Gear',
    tip: 'Student orgs, youth groups, sports clubs — jerseys, sweatpants, hoodies. Trending picks for groups that care about looking good together.',
    blurb: 'From practice to game day, gear that makes your group look and feel like a team.',
  },
  {
    name: 'Reselling',
    tip: 'Building your own brand? T-shirts, hoodies, and tote bags with the quality and consistency you need for a product line your customers will come back for.',
    blurb: 'Products built for your label — quality and style your customers will come back for.',
  },
];

const EXAMPLE_QUERIES = [
  "I'm looking for a MagSafe power bank for iphone",
  "Pink elegant women's polo shirt",
  'Large ceramic mug for the office',
  'Premium water bottle for sport',
  'Nike dri-fit swag',
  'backpack from $120 to $200',
];

interface NeuralSearchProduct {
  style_id: number;
  product_id: number;
  name: string;
  product_type: string | null;
  manufacturer: string | null;
  primary_category_name: string | null;
  style_card_image_url: string | null;
  link: string | null;
  brand: string[] | null;
  rating_score: number | null;
  rating_count: number | null;
  price: number | null;
  confidenceScore: number | null;
  status: string;
}

interface NeuralSearchResponse {
  query: string;
  total: number;
  products: NeuralSearchProduct[];
}

interface UseCaseResponse {
  useCase: string;
  total: number;
  products: NeuralSearchProduct[];
}

type ChatEntry = { role: 'user'; text: string } | { role: 'ai'; text: string; products?: NeuralSearchProduct[]; total?: number } | { role: 'welcome' };

@Component({
  tag: 'ci-ask-ai',
  styleUrl: 'ci-ask-ai.scss',
  scoped: true,
})
export class CiAskAi {
  @Element() $el: HTMLElement;
  @State() isOpen: boolean = false;
  @State() message: string = '';
  @State() entries: ChatEntry[] = [];
  @State() selectedCategory: string | null = null;
  @State() isLoading: boolean = false;
  @State() thinkingDots: number = 1;
  @State() isWelcomePinned: boolean = false;

  private inputRef: HTMLTextAreaElement;
  private messagesRef: HTMLDivElement;
  private thinkingInterval: number;
  private historyIndex: number = -1;
  private draftMessage: string = '';
  connectedCallback() {
    if (isBrowser) {
      this.entries = this.loadHistory();
    }
  }

  private loadHistory(): ChatEntry[] {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      return JSON.parse(raw) as ChatEntry[];
    } catch {
      return [];
    }
  }

  private saveHistory() {
    try {
      const persistable = this.entries.filter(e => e.role !== 'welcome');
      localStorage.setItem(STORAGE_KEY, JSON.stringify(persistable));
    } catch {
      // storage full or unavailable — silently ignore
    }
  }

  @Listen('keydown', { target: 'document' })
  handleDocumentKeyDown(event: KeyboardEvent) {
    if (event.key === 'Escape' && this.isOpen && !this.isLoading) {
      this.closePopup();
      return;
    }

    if (event.key === 'Tab' && this.isOpen) {
      this.trapFocus(event);
    }
  }

  private trapFocus(e: KeyboardEvent) {
    const popup = this.$el.querySelector('.ask-ai-popup') as HTMLElement;
    if (!popup) return;

    const focusable = popup.querySelectorAll<HTMLElement>('button:not([disabled]), textarea:not([disabled]), a[href], [tabindex]:not([tabindex="-1"])');
    if (!focusable.length) return;

    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault();
      last.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault();
      first.focus();
    }
  }

  private openPopup = (e: MouseEvent) => {
    if (!isBrowser) return;
    trackAnalyticsEvent(e);
    this.isWelcomePinned = false;
    this.addWelcomeEntry();
    this.isOpen = true;
    document.body.style.overflow = 'hidden';
    requestAnimationFrame(() => {
      this.scrollToBottom();
      this.inputRef?.focus();
    });
  };

  private closePopup = () => {
    this.isOpen = false;
    this.isWelcomePinned = false;
    document.body.style.overflow = '';
  };

  private clearHistory = () => {
    if (!window.confirm('Clear chat history?')) return;
    this.stopThinking();
    this.entries = [{ role: 'welcome' }];
    this.message = '';
    this.selectedCategory = null;
    this.isLoading = false;
    this.isWelcomePinned = false;
    try {
      localStorage.removeItem(STORAGE_KEY);
    } catch {
      // silently ignore
    }
  };

  private handleBackdropClick = (e: MouseEvent) => {
    if (this.isLoading) return;
    if ((e.target as HTMLElement).classList.contains('ask-ai-overlay')) {
      this.closePopup();
    }
  };

  private handleInput = (e: Event) => {
    this.message = (e.target as HTMLTextAreaElement).value;
  };

  private getUserPrompts(): string[] {
    return this.entries.filter(e => e.role === 'user').map(e => e.text);
  }

  private handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      this.handleSend();
      return;
    }

    const prompts = this.getUserPrompts();
    if (!prompts.length) return;

    if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (this.historyIndex === -1) {
        this.draftMessage = this.message;
      }
      const nextIndex = Math.min(this.historyIndex + 1, prompts.length - 1);
      this.historyIndex = nextIndex;
      this.message = prompts[prompts.length - 1 - nextIndex];
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      const nextIndex = this.historyIndex - 1;
      if (nextIndex < 0) {
        this.historyIndex = -1;
        this.message = this.draftMessage;
      } else {
        this.historyIndex = nextIndex;
        this.message = prompts[prompts.length - 1 - nextIndex];
      }
    }
  };


  private addWelcomeEntry() {
    const last = this.entries[this.entries.length - 1];
    if (last?.role === 'welcome') return;
    this.entries = [...this.entries, { role: 'welcome' }];
  }

  private toggleCategory = (category: string) => {
    if (this.isLoading) return;

    if (this.selectedCategory === category) {
      this.selectedCategory = null;
      return;
    }

    this.selectedCategory = category;
    this.fetchUseCaseProducts(category);
  };

  private handleExampleClick = (query: string) => {
    this.message = query;
    requestAnimationFrame(() => {
      this.inputRef?.focus();
    });
  };

  private startThinking() {
    this.thinkingDots = 1;
    this.thinkingInterval = window.setInterval(() => {
      this.thinkingDots = (this.thinkingDots % 3) + 1;
    }, 250);
  }

  private stopThinking() {
    window.clearInterval(this.thinkingInterval);
  }

  private scrollToBottom() {
    requestAnimationFrame(() => {
      if (this.messagesRef) {
        this.messagesRef.scrollTop = this.messagesRef.scrollHeight;
      }
    });
  }

  private scrollToLastUserMessage() {
    requestAnimationFrame(() => {
      if (!this.messagesRef) return;
      const userMessages = this.messagesRef.querySelectorAll('.ask-ai-message--user');
      const last = userMessages[userMessages.length - 1] as HTMLElement;
      if (last) {
        this.messagesRef.scrollTop = last.offsetTop - this.messagesRef.offsetTop;
      }
    });
  }

  private async fetchProducts(query: string): Promise<NeuralSearchResponse> {
    const url = new URL(NEURAL_SEARCH_URL);
    url.searchParams.set('q', query);
    url.searchParams.set('limit', '12');

    const response = await fetch(url.toString());
    if (!response.ok) {
      throw new Error(`Search failed: ${response.status}`);
    }
    return response.json();
  }

  private async fetchUseCaseProducts(useCase: string): Promise<void> {
    this.entries = [...this.entries, { role: 'user', text: `Search best products for ${useCase}` }];
    this.saveHistory();
    this.isLoading = true;
    this.startThinking();
    this.scrollToBottom();

    try {
      const url = new URL(`${NEURAL_SEARCH_URL}/use-case/${encodeURIComponent(useCase)}`);
      url.searchParams.set('limit', '12');

      const response = await fetch(url.toString());
      if (!response.ok) {
        throw new Error(`Search failed: ${response.status}`);
      }
      const result: UseCaseResponse = await response.json();

      if (result.products.length > 0) {
        const tag = CATEGORY_TAGS.find(t => t.name === useCase);
        const blurb = tag?.blurb || `Best products for ${result.useCase}`;
        this.entries = [...this.entries, { role: 'ai', text: blurb, products: result.products, total: result.total }];
      } else {
        this.entries = [...this.entries, { role: 'ai', text: `No products found for "${result.useCase}". Try a different category.` }];
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      this.entries = [...this.entries, { role: 'ai', text: `Search failed: ${errorMessage}. Please try again.` }];
    } finally {
      this.stopThinking();
      this.isLoading = false;
      this.selectedCategory = null;
      this.isWelcomePinned = true;
      this.saveHistory();
      this.scrollToLastUserMessage();
    }
  }

  private handleSend = async () => {
    const trimmed = this.message.trim();
    if (!trimmed || this.isLoading) return;

    this.entries = [...this.entries, { role: 'user', text: trimmed }];
    this.saveHistory();
    this.message = '';
    this.historyIndex = -1;
    this.draftMessage = '';
    this.isLoading = true;
    this.startThinking();
    this.scrollToBottom();

    try {
      const result = await this.fetchProducts(trimmed);

      if (result.products.length > 0) {
        this.entries = [
          ...this.entries,
          { role: 'ai', text: `Found ${result.total} product${result.total !== 1 ? 's' : ''} for "${result.query}"`, products: result.products, total: result.total },
        ];
      } else {
        this.entries = [...this.entries, { role: 'ai', text: `No products found for "${result.query}". Try a different description.` }];
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      this.entries = [...this.entries, { role: 'ai', text: `Search failed: ${errorMessage}. Please try again.` }];
    } finally {
      this.stopThinking();
      this.isLoading = false;
      this.isWelcomePinned = true;
      this.saveHistory();
      this.scrollToLastUserMessage();
    }
  };

  private renderSendIcon() {
    return (
      <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none">
        <path d="M2.01 21L23 12L2.01 3L2 10L17 12L2 14L2.01 21Z" fill="currentColor" />
      </svg>
    );
  }

  private renderWelcomeEntry() {
    return [
      <span class="ask-ai-message-label">Shopping Assistant</span>,
      <div class="ask-ai-welcome-bubble">
        <span>What type of products are you looking for?</span>
        <div class={{ 'ask-ai-welcome-tags': true, 'ask-ai-welcome-tags--disabled': this.isLoading }}>
          {CATEGORY_TAGS.map(cat => (
            <div class="ask-ai-category-tag-wrapper">
              <button
                class={{
                  'ask-ai-category-tag': true,
                  'ask-ai-category-tag--selected': this.selectedCategory === cat.name,
                }}
                onClick={() => this.toggleCategory(cat.name)}
                type="button"
                disabled={this.isLoading}
              >
                {cat.name}
                <span class="ask-ai-category-tag-tip-icon">
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none">
                    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z" fill="currentColor" />
                  </svg>
                </span>
              </button>
              <div class="ask-ai-category-tag-tooltip">{cat.tip}</div>
            </div>
          ))}
        </div>
      </div>,
    ];
  }

  private renderExampleQueries() {
    return (
      <div class="ask-ai-examples">
        <span class="ask-ai-examples-label">Try asking:</span>
        <div class="ask-ai-examples-list">
          {EXAMPLE_QUERIES.map(query => (
            <button class="ask-ai-example" onClick={() => this.handleExampleClick(query)} type="button">
              <svg class="ask-ai-example-icon" xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none">
                <path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" fill="currentColor" />
              </svg>
              <span>{query}</span>
            </button>
          ))}
        </div>
      </div>
    );
  }

  private formatConfidence(score: number | null): string {
    if (score == null) return '';
    return `${Math.round(score)}%`;
  }

  private renderProductCard(product: NeuralSearchProduct) {
    const imageUrl = product.style_card_image_url || '';
    const productUrl = product.link ? `${process.env.CI_HOSTNAME || ''}${product.link}` : '#';
    const confidence = this.formatConfidence(product.confidenceScore);

    return (
      <a class="ask-ai-product-card" href={productUrl} target="_blank" rel="noopener noreferrer">
        {confidence && (
          <div class="ask-ai-product-confidence">
            <span class="ask-ai-product-confidence-label">Confidence:&nbsp;</span>
            {confidence}
          </div>
        )}
        <div class="ask-ai-product-image-wrapper">
          {imageUrl ? (
            <img class="ask-ai-product-image" src={imageUrl} alt={product.name} loading="lazy" />
          ) : (
            <div class="ask-ai-product-image-placeholder">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
                <path d="M21 19V5c0-1.1-.9-2-2-2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2zM8.5 13.5l2.5 3.01L14.5 12l4.5 6H5l3.5-4.5z" fill="currentColor" />
              </svg>
            </div>
          )}
        </div>
        <div class="ask-ai-product-info">
          <span class="ask-ai-product-name">{product.name}</span>
          {product.price != null && <span class="ask-ai-product-price">${product.price.toFixed(2)}</span>}
          {product.primary_category_name && <span class="ask-ai-product-category">{product.primary_category_name}</span>}
          {product.manufacturer && <span class="ask-ai-product-manufacturer">{product.manufacturer}</span>}
        </div>
      </a>
    );
  }

  private renderProductsGrid(products: NeuralSearchProduct[]) {
    return <div class="ask-ai-products-grid">{products.map(product => this.renderProductCard(product))}</div>;
  }

  private renderLoadingIndicator() {
    const dots = '.'.repeat(this.thinkingDots);
    return (
      <div class="ask-ai-thinking">
        <span class="ask-ai-thinking-text">Thinking{dots}</span>
      </div>
    );
  }

  private renderEntry(entry: ChatEntry) {
    if (entry.role === 'welcome') {
      return this.renderWelcomeEntry();
    }
    if (entry.role === 'ai') {
      return (
        <div class="ask-ai-message-group">
          <span class="ask-ai-message-label">Shopping Assistant</span>
          <div class="ask-ai-message ask-ai-message--ai">
            <span>{entry.text}</span>
            {entry.products && entry.products.length > 0 && this.renderProductsGrid(entry.products)}
          </div>
        </div>
      );
    }
    return (
      <div class="ask-ai-message ask-ai-message--user">
        <span>{entry.text}</span>
      </div>
    );
  }

  render() {
    return [
      <div class="ask-ai-btn-wrapper">
        <button class="ask-ai-btn" onClick={this.openPopup} data-section="ask-ai" data-link="ask-ai" data-testid="ask-ai-btn" aria-label="Shopping Assistant">
          <span class="ask-ai-btn-text">Shopping Assistant</span>
        </button>
      </div>,
      this.isOpen && (
        <div class="ask-ai-overlay" onClick={this.handleBackdropClick}>
          <div class={{ 'ask-ai-popup': true, 'ask-ai-popup--loading': this.isLoading }} role="dialog" aria-label="Shopping Assistant Chat" aria-modal="true">
            <div class="ask-ai-popup-header">
              <div class="ask-ai-popup-title">
                <span>Shopping Assistant</span>
              </div>
              <div class="ask-ai-popup-header-actions">
                <button class="ask-ai-popup-clear" onClick={this.clearHistory} disabled={this.isLoading} aria-label="Clear history">
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none">
                    <path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z" fill="currentColor" />
                  </svg>
                  <span>Clear</span>
                </button>
                <button class="ask-ai-popup-close" onClick={this.closePopup} disabled={this.isLoading} aria-label="Close">
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none">
                    <path d="M19 6.41L17.59 5L12 10.59L6.41 5L5 6.41L10.59 12L5 17.59L6.41 19L12 13.41L17.59 19L19 17.59L13.41 12L19 6.41Z" fill="currentColor" />
                  </svg>
                </button>
              </div>
            </div>

            <div class="ask-ai-popup-body" ref={el => (this.messagesRef = el)}>
              {this.isWelcomePinned && (
                <div class="ask-ai-welcome ask-ai-welcome--pinned">
                  <div class={{ 'ask-ai-welcome-tags': true, 'ask-ai-welcome-tags--disabled': this.isLoading }}>
                    {CATEGORY_TAGS.map(cat => (
                      <div class="ask-ai-category-tag-wrapper">
                        <button
                          class={{
                            'ask-ai-category-tag': true,
                            'ask-ai-category-tag--selected': this.selectedCategory === cat.name,
                          }}
                          onClick={() => this.toggleCategory(cat.name)}
                          type="button"
                          disabled={this.isLoading}
                        >
                          {cat.name}
                          <span class="ask-ai-category-tag-tip-icon">
                            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none">
                              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z" fill="currentColor" />
                            </svg>
                          </span>
                        </button>
                        <div class="ask-ai-category-tag-tooltip">{cat.tip}</div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
              <div class="ask-ai-popup-messages">
                {this.entries.map(entry => this.renderEntry(entry))}
                {this.isLoading && this.renderLoadingIndicator()}
              </div>
            </div>

            {this.renderExampleQueries()}

            <div class="ask-ai-popup-input-area">
              <div class="ask-ai-popup-input-wrapper">
                <textarea
                  ref={el => (this.inputRef = el)}
                  class="ask-ai-popup-input"
                  placeholder="Describe your perfect product ..."
                  value={this.message}
                  onInput={this.handleInput}
                  onKeyDown={this.handleKeyDown}
                  rows={1}
                  maxLength={120}
                  disabled={this.isLoading}
                />
              </div>
              <button
                class={{
                  'ask-ai-popup-send': true,
                  'ask-ai-popup-send--active': this.message.trim().length > 0 && !this.isLoading,
                }}
                onClick={this.handleSend}
                disabled={!this.message.trim() || this.isLoading}
                aria-label="Send message"
              >
                {this.renderSendIcon()}
              </button>
            </div>
          </div>
        </div>
      ),
    ];
  }
}

